    const drawWorldMapCode = drawWorldMapStart >= 0 && drawWorldMapEnd > drawWorldMapStart ? uiCode.slice(drawWorldMapStart, drawWorldMapEnd) : '';
    const drawEquipmentStart = uiCode.indexOf('    drawEquipmentCanvas(ctx, x, y, w) {');
