    const withMockRandom = (values, callback) => {
      const originalRandom = Math.random;
      let index = 0;
      let fallback = 0;
      Math.random = () => {
        if (index < values.length) {
          const value = values[index];
          index += 1;
          return value;
        }
        fallback = (fallback + 137) % 997;
        return fallback / 997;
      };
      try {
        return callback();
      } finally {
        Math.random = originalRandom;
      }
    };
